/**
 * @generated by @flusk/cli
 * Resources generator - creates repository files and database migrations
 */

import { resolve } from 'node:path';
import { writeFile, mkdir, readdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { getMigrationNumber } from './utils.js';
import { generateRepositoryTemplate } from '../templates/repository.template.js';
import { generateMigrationTemplate } from '../templates/migration.template.js';
import { toTableName } from './utils.js';

export interface GeneratorResult {
  path: string;
  content: string;
}

export async function generateResources(
  entityPath: string,
  entityName: string
): Promise<GeneratorResult[]> {
  const results: GeneratorResult[] = [];

  // Generate repository
  const repoResult = await generateRepository(entityName);
  results.push(repoResult);

  // Generate migration
  const migrationResult = await generateMigration(entityName);
  results.push(migrationResult);

  return results;
}

async function generateRepository(entityName: string): Promise<GeneratorResult> {
  const outputDir = resolve(process.cwd(), 'packages/resources/src/repositories');
  const outputPath = resolve(outputDir, `${entityName}.repository.ts`);

  if (!existsSync(outputDir)) {
    await mkdir(outputDir, { recursive: true });
  }

  const content = generateRepositoryTemplate(entityName);
  await writeFile(outputPath, content, 'utf-8');

  return {
    path: `resources/repositories/${entityName}.repository.ts`,
    content
  };
}

async function generateMigration(entityName: string): Promise<GeneratorResult> {
  const migrationsDir = resolve(process.cwd(), 'packages/resources/src/migrations');
  const tableName = toTableName(entityName);

  if (!existsSync(migrationsDir)) {
    await mkdir(migrationsDir, { recursive: true });
  }

  // Get existing migrations to determine number
  const existingFiles = existsSync(migrationsDir)
    ? await readdir(migrationsDir)
    : [];

  const migrationNumber = getMigrationNumber(existingFiles);
  const fileName = `${migrationNumber}_${tableName}.sql`;
  const outputPath = resolve(migrationsDir, fileName);

  const content = generateMigrationTemplate(entityName);
  await writeFile(outputPath, content, 'utf-8');

  return {
    path: `resources/migrations/${fileName}`,
    content
  };
}
